head.script:
/* ★AIcraft guide★    
스크립트 수작업 유의사항
*/


////////////////////////////////////////////////////////////////////////////////////////////
// History
////////////////////////////////////////////////////////////////////////////////////////////
// 20120712 : 법인KB스타 대표및가족 선정등록 기능 추가(탭 방식)
// 20120716 : 그리드의 자격해제년월일 (+6개월) 계산 추가
// 20120717 : 그리드의 해제시각 속성 변경
//          : 그리드에 '등록구분' 한글명 기능 추가
//          : 법인사업자번호 입력시, 고객유형 체크(법인사업자만 가능)
//          : 그리드에 '자격해제년월일' 출력 매핑
// 20120718 : 선정사유가 '법인대표자'이외이면서, 부고객번호와 주고객번호 같을때 오류메세지
//          : S-MVP와 법인KB스타 중복 등록 방지 기능 추가
// 20120719 : 법인스타 가족정보 불러오기...활성화 복원 기능 정비
//          : S-MVP 영업점한도 그룹박스 위치 조정
// 20120720 : 해제는 등록점에서만 가능하도록 조건 추가
// 20120723 : 한도 초과 오류 메세지 내용 변경 및 S-MVP/개인KB스타 등록에도 기능 추가
//          : 중복 등록 오류 안내 메세지 내용 변경
// 20120725 : 법인KB스타 그리스에서 항목 선택시, 등급구분 콤보박스 비활성화 처리
//          : '가족관계 없음' 버튼 숨기기 및 비활성화
//          : 법인대표자주민번호가 '개인'만 가능하도록 에러메세지 추가
// 20120730 : 개인KB스타 영업점 한도 타이틀명 수정
// 20120813 : 법인KB스타 그리드의 등록,해제 한글명 표시 조건 변경
// 20150302 : 본인확인번호 및 KB-PIN 적용(P20141608590 - 고객정보번호 활용 확대)
// 20150618 : 본부선정등급 값 오타 수정(프리미업스타 -> 프리미엄스타)
//          : 연계서식 패널 위치 조정(개인KB스타 탭 밖)
// 20180816 : 영업점선정 퇴직직원특별선정등급 값 수정 및 관리부점 변경
// 20190717 : 영업점선정 기준추가 - 우량가망고객(본부부서)
////////////////////////////////////////////////////////////////////////////////////////////

scwin.SavedData;
scwin.strDAmndBrncd = dmndBrncd.getValue();
scwin.LegthStrDAmndBrncd = scwin.strDAmndBrncd.length;

scwin.onpageload = function() {
	scwin.OnInitScreen();
};

scwin.onpageunload = function() {};

//==================================화면로드시==============================================

scwin.OnInitScreen = async function() {
    //1. 좌측프레임에서 들어오는 고객식별자, 고객관리번호로 조회처리를 한다. DATA가  없으면 빈 화면을 출력한다
    //1. (S-MVP 영업점선정고객조회 : KAA0441041)거래처리
    scwin.serchNoDstcd_OnItemChanged();
    cuniqno.setValue("");
    selfConfirmNo.setValue(""); //본인확인번호
    custnm.setValue("");
    custIdnfr.setValue("");
    custMgtNo.setValue("");
    ppsnBsnoJntRpsnYn.setValue("");

    //화면 초기화(S-MVP 탭)
    GroupBox1.setValue("");
    GroupBox2.setValue("");
    GroupBox_Gaein3.setValue("");

    // 영업점선정등급 콤보박스
    //bbrnChoicGrd.SetComboItems("0-해당무;1-MVP스타;2-로얄스타;3-골드스타;5-프리미엄스타;9-일반고객;");
    bbrnChoicGrd.SetComboItems("0-해당무;");
    regiRevocDstic1.setSelectedIndex(0);
    regiRevocDstic2.setSelectedIndex(0);

    //choicBase.SetCurSel(0);		// 선정기준
    bbrnChoicGrd.setSelectedIndex(0);
    athorStus.setSelectedIndex(0);
    GroupBox_Hidden.setValue(""); //히든 컨트롤 그룹

    //법인KB스타 탭
    GroupBox_Bubin1.setValue("");
    GroupBox_Bubin2.setValue("");
    GroupBox_Bubin3.setValue("");
    GroupBox_Hidden.setValue("");
    dlt_dataBook.removeAll();
    coprKsrDstic_tab2.setSelectedIndex(0); //법인KB스타관계구분(선정기준)
    bbrnChoicGrd_tab2.setSelectedIndex(0); //법인KB스타선정등급(영업점선정등급)
    regiYn_tab2.setSelectedIndex(0); //법인KB스타 등록해제구분


    if ($c.iz.data.trim(custIdnfr.getValue()) != "" && $c.iz.data.trim(custMgtNo.getValue()) != "") {
        $c.iz.tran.setTranID("KAA0441041");
        await $c.tran.ASend();
    }
    athorDte.setValue($c.user.getUserProfile('tranBaseYmd'));
    athorBrncd.setValue($c.user.getUserProfile('userBzwkBrncd'));
    athorBrnName.setValue($c.user.getUserProfile('userBzwkBrnName'));
    athorEmnm.setValue($c.user.getUserProfile('empName'));
    if (regiRevocDstic1.getValue() == "2") {
        choicBase.setDisabled(true); // 선정기준
        bbrnChoicGrd.setDisabled(true);
    } else {
        choicBase.setDisabled(false); // 선정기준
        bbrnChoicGrd.setDisabled(false);
        if (choicBase.setValue("00")) {
            bbrnChoicGrd.setDisabled(true);
        }
        if ($c.user.getUserProfile('userBzwkBrncd') == "3869" || $c.user.getUserProfile('userBzwkBrncd') == "1764") {
            choicBase.AddComboItems("12-우량가망고객(본부부서)");
        }
    }

    // 2017.01.23 부점명 변경 반영(3140 마케팅부-> 9607 데이터분석부)
    //2017-12-28 부점코드변경 9607 -> 3869
    if ($c.user.getUserProfile('userBzwkBrncd') == "3869" || $c.user.getUserProfile('userBzwkBrncd') == "1764") {
        // 9607 : 데이터분석부, 4055 : 여신IT개발부 --> 1764: 정보개발부
        Button2.setDisabled(false); // 승인등록 버튼
        GroupBox2.setStyle(display, "");
        GroupBox_Gaein4.setStyle(display, "");
    } else {
        Button2.setDisabled(true); // 승인등록 버튼
        GroupBox2.setStyle(display, "none"); // 본부승인 그룹박스를 숨김
        GroupBox_Gaein4.setStyle(display, "none"); // 본부승인 그룹박스를 숨김
    }
    choicBase.setSelectedIndex(0); // 선정기준
};

scwin.serchNoDstcd_OnItemChanged = function(info) {
    //검색구분
    if (serchNoDstcd.getValue() == '3') {
        //고객정보번호 선택시
        serchNo.hide();
        serchCustIdnfr.show('');
        serchCustMgtNo.show('');
        serchCustIdnfr.focus();
        serchCustIdnfr.setMandatory(true);
        serchNo.setMandatory(false);
        Button5.show('');
    } else {
        serchNo.show('');
        serchCustIdnfr.hide();
        serchCustMgtNo.hide();
        serchNo.focus();
        serchCustIdnfr.setMandatory(false);
        serchNo.setMandatory(true);
        Button5.hide();
    }
};

scwin.MakeMgtNo = function(strMgtNo) {
    var tmpMgtNo = strMgtNo.toString();
    var tmpLength = 6;
    if (tmpMgtNo == "") return "";
    tmpLength = tmpLength - tmpMgtNo.length;
    for (var i = 1; i < tmpLength; i++) {
        tmpMgtNo = "0" + tmpMgtNo;
    }
    return tmpMgtNo;
};


scwin.OnSendKey = async function() {
    // 실행버튼

    cuniqno.setValue("");
    selfConfirmNo.setValue(""); //본인확인번호
    custnm.setValue("");
    cuniqno.setValue("");
    custnm.setValue("");
    custIdnfr.setValue("");
    custMgtNo.setValue("");
    ppsnBsnoJntRpsnYn.setValue("");

    //화면초기화
    GroupBox1.setValue("");
    GroupBox2.setValue("");
    GroupBox_Gaein3.setValue("");
    GroupBox_Hidden.setValue(""); //히든 컨트롤 그룹

    //법인KB스타 탭
    GroupBox_Bubin1.setValue("");
    GroupBox_Bubin2.setValue("");
    GroupBox_Bubin3.setValue("");
    GroupBox_Hidden.setValue("");
    dlt_dataBook.removeAll();
    coprKsrDstic_tab2.setSelectedIndex(0); //법인KB스타관계구분(선정기준)
    bbrnChoicGrd_tab2.setSelectedIndex(0); //법인KB스타선정등급(영업점선정등급)
    regiYn_tab2.setSelectedIndex(0); //법인KB스타 등록해제구분

    coprKsrDstic_tab2.setDisabled(false); //법인KB스타관계구분(선정기준)
    bbrnChoicGrd_tab2.setDisabled(false); //법인KB스타선정등급구분코드
    //mainCuniqno_tab2.Enabled = true;		//주고객고유번호
    mainCustIdnfr_tab2.setReadOnly(false); //주고객식별자(법인대표자)
    //coprBzmanUniqno_tab2.Enabled = true;	//법인사업자번호
    coprBzmanUniqno_tab2.setReadOnly(false); //법인사업자번호

    Button_tab2_GetFamily.setDisabled(false); //법인스타 가족정보 불러오기 버튼

    if (serchNoDstcd.getValue() == '3') {
        serchNo.setValue(serchCustIdnfr.getValue() + scwin.MakeMgtNo(serchCustMgtNo.getValue()));
    }
    $c.iz.tran.setTranID("KAA0441041");
    $c.iz.tran.noLockScreen();
    await $c.tran.ASend();


    //조회후 결과값 save
    scwin.SavedData = this.GetScreenControlData();
};

//==================================버튼이벤트==========================================

scwin.Button1_OnClick = async function(e) {
    //개인KB스타 고객등록 버튼
    //1. (S-MVP영업점선정고객등록 : KAA0641061)거래처리

    //등록시 고객식별자체크
    if (custIdnfr.getValue() == "") {
        $c.iz.data.message("KB-PIN이 없습니다. 조회 후 처리하시기 바랍니다.");
        serchNo.focus();
        return false;
    }

    //매월10일전 2영업일 오류처리
    if (jobPrhbYn.getValue() == "Y") {
        $c.iz.data.alert("매월 스타클럽 등급선정일 전 2영업일은 등급선정작업으로 인해 거래가 제한됩니다.", "알림");
        serchNo.focus();
        return false;
    }

    //등록,해제선택
    if (regiRevocDstic1.getValue() == "") {
        $c.iz.data.alert("등록, 해제를 선택하여 주십시요", "");
        regiRevocDstic1.focus();
        return false;
    }
    if (regiRevocDstic1.getValue() == "1") {
        //등록거래이면서
        if (choicInquryDstcd.getValue() == 'K') {
            // 이미 법인KB스타 등록 고객
            $c.iz.data.alert("현재 법인KB스타대표/가족 등급을 보유하고 있는 고객입니다.\n재선정 필요시 기존 선정등록 내역을 해제 처리 후 재등록하시기 바랍니다.", "중복 선정 불가 안내");
            return false;
        }
    } else if (regiRevocDstic1.getValue() == "2") {
        //해제거래이면서


        //해제하는 부점이, 관리점 또는 등록점과 동일한지 체크
        if ($c.user.getUserProfile('userBzwkBrncd') != regiBrn.getValue() && $c.user.getUserProfile('userBzwkBrncd') != mgtBrncd.getValue()) {
            $c.iz.data.alert("등록했던 부점 또는 관리부점에서만 해제가 가능합니다.\n등록점 : " + regiBrn.getValue() + ", 관리점 : " + mgtBrncd.getValue() + ", 거래점 : " + $c.user.getUserProfile('userBzwkBrncd'), "안내");
            return false;
        }

        //해제버튼 클릭 시 안내 메시지 팝업
        if ($c.iz.data.confirm("선정 해제시 해당 고객의 등급은 당월 은행 실질등급으로 변경됩니다.\n가족합산등급 등 최고등급을 보유하고 있는 고객일 경우 해당 등급은 매월 10일에 반영되오니 고객응대에 참고하시기 바랍니다.", "해제 안내") != true) {
            //취소 선택했을 때
            return false;
        }
    }
    var CurrData = this.GetScreenControlData();

    //	alert("변경전내용 SavedData ===>"+SavedData, "안내");	
    //	alert("변경후내용 CurrData  ===>"+CurrData, "안내");		

    if (CurrData == scwin.SavedData) {
        $c.iz.data.alert("변경사항이 없습니다", "");
        return false;
    }
    if (athorStus.getValue() != '1') {
        if (regiRevocDstic1.getValue() == '1') {
            if (choicBase.getValue() == '04') {
                // 선정기준 (04:S-MVP(사회지도층인사))

                // 2017.01.23 부점명 변경 반영(3140 마케팅부-> 9607 데이터분석부)
                //2017-12-28 부점명 변경 9607 데이터분석부 -> 3869 개인고객부
                //alert("S-MVP(사회지도층인사)선정 등록은 개인고객부 심사 승인 사항으로 \n  개인고객부에 요청후 선정 등록 바랍니다.","알림");
                $c.iz.data.alert("사회지도층인사 선정 등록은 개인고객부 심사 승인 사항으로 \n  개인고객부에 요청후 선정 등록 바랍니다.", "알림");
                return false;
            } else if (choicBase.getValue() == '05') {
                // 선정기준 (05:S-MVP(당행전직임원))

                //alert("S-MVP(당행전직임원)선정 등록은 개인고객부 심사 승인 사항으로 \n  개인고객부에 요청후 선정 등록 바랍니다.","알림");
                $c.iz.data.alert("당행전직임원 선정 등록은 개인고객부 심사 승인 사항으로 \n  개인고객부에 요청후 선정 등록 바랍니다.", "알림");
                return false;
            } else if (choicBase.getValue() == '11') {
                // 선정기준 (11:S-MVP(당행전직본부장))

                //alert("S-MVP(당행전직본부장)선정 등록은 개인고객부 심사 승인 사항으로 \n  개인고객부에 요청후 선정 등록 바랍니다.","알림");
                $c.iz.data.alert("당행전직본부장 선정 등록은 개인고객부 심사 승인 사항으로 \n  개인고객부에 요청후 선정 등록 바랍니다.", "알림");
                return false;
            }
        }
    }

    //선정기준체크
    if (choicBase.getValue() == '00') {
        // 선정기준 (00:해당무)
        $c.iz.data.alert("선정기준을 00(해당무)로 등록할 수 없습니다. 선정기준을 확인해주세요.", "알림");
        choicBase.focus();
        return false;
    }

    //영업점선정등급체크
    if (bbrnChoicGrd.getValue() == '0') {
        $c.iz.data.alert("영업점선정등급을 0(해당무)로 등록할 수 없습니다. 영업점선정등급을 확인해주세요.", "알림");
        bbrnChoicGrd.focus();
        return false;
    }
    $c.iz.tran.setTranID("KAA0641061");
    $c.iz.tran.noLockScreen();
    await $c.tran.ASend();
};

scwin.Button2_OnClick = async function(e) {
    //승인등록 버튼
    //1. (S-MVP본부승인등록 : KAA0641461)거래처리

    //등록시고객식별자체크
    if (custIdnfr.getValue() == "") {
        $c.iz.data.message("KB-PIN이 없습니다. 조회 후 처리하시기 바랍니다.");
        serchNo.focus();
        return false;
    }

    //매월10일전 2영업일 오류처리
    if (jobPrhbYn.getValue() == "Y") {
        $c.iz.data.alert("매월 스타클럽 등급선정일 전 2영업일은 등급선정작업으로 인해 거래가 제한됩니다.", "알림");
        serchNo.focus();
        return false;
    }
    if (regiRevocDstic2.getValue() == "") {
        $c.iz.data.alert("등록, 해제를 선택하여 주십시요", "");
        regiRevocDstic2.focus();
        return false;
    }
    if (regiRevocDstic2.getValue() == "1") {
        // 등록거래이면서
        //등록가능고객수 체크
        if (bbrnChoicGrd.getValue() == '1') {
            //MVP
            if (sBrnRAbilNoitm1.getValue() <= 0) {
                //MVP 한도
                $c.iz.data.alert("영업점 선정 한도 초과로 등록이 불가합니다.(MVP)", "한도 초과 에러");
                return false;
            }
        } else if (bbrnChoicGrd.getValue() == '2') {
            //로얄
            if (sBrnRAbilNoitm2.getValue() <= 0) {
                //로얄 한도
                $c.iz.data.alert("영업점 선정 한도 초과로 등록이 불가합니다.(로얄)", "한도 초과 에러");
                return false;
            }
        } else if (bbrnChoicGrd.getValue() == '3') {
            //골드
            if (sBrnRAbilNoitm3.getValue() <= 0) {
                //골드 한도
                $c.iz.data.alert("영업점 선정 한도 초과로 등록이 불가합니다.(골드)", "한도 초과 에러");
                return false;
            }
        } else if (bbrnChoicGrd.getValue() == '4') {
            //프리미엄
            if (sBrnRAbilNoitm4.getValue() <= 0) {
                //프리미엄 한도
                $c.iz.data.alert("영업점 선정 한도 초과로 등록이 불가합니다.(프리미엄)", "한도 초과 에러");
                return false;
            }
        }
    }
    var CurrData = this.GetScreenControlData();

    //	alert("변경전내용 SavedData ===>"+SavedData, "안내");	
    //	alert("변경후내용 CurrData  ===>"+CurrData, "안내");		

    if (CurrData == scwin.SavedData) {
        $c.iz.data.alert("변경사항이 없습니다", "");
        return false;
    }
    $c.iz.tran.setTranID("KAA0641461");
    $c.iz.tran.noLockScreen();
    await $c.tran.ASend();
};


