scwin.OnEndTran = async function() {
    //S-MVP영업점선정고객등록
    if ($c.iz._tran.tranId == "KAA0641061" && $c.iz._tran.bError == false) {
        cuniqno.setValue("");
        selfConfirmNo.setValue(""); //본인확인번호
        custnm.setValue("");
        cuniqno.setValue("");
        custnm.setValue("");
        custIdnfr.setValue("");
        custMgtNo.setValue("");
        ppsnBsnoJntRpsnYn.setValue("");
        GroupBox1.setValue("");
        GroupBox2.setValue("");
        GroupBox_Hidden.setValue(""); //히든 컨트롤 그룹

        $c.iz.tran.setTranID("KAA0441041");
        $c.iz.tran.noLockScreen();
        await $c.tran.ASend();

        //조회후 결과값 save
        scwin.SavedData = this.GetScreenControlData();
    }

    //법인KB스타대표개인등급선정고객등록
    if ($c.iz._tran.tranId == "KAA0641661" && $c.iz._tran.bError == false) {
        serchNo.setValue(mainCustIdnfr_tab2.getValue()); //주고객식별자
        serchCustIdnfr.setValue(mainCustIdnfr_tab2.getValue()); //주고객식별자
        serchNoDstcd.setValue('3');
        cuniqno.setValue("");
        selfConfirmNo.setValue(""); //본인확인번호
        custnm.setValue("");
        cuniqno.setValue("");
        custnm.setValue("");
        custIdnfr.setValue("");
        custMgtNo.setValue("");
        ppsnBsnoJntRpsnYn.setValue("");
        GroupBox_Hidden.setValue(""); //히든 컨트롤 그룹

        //법인KB스타 탭
        GroupBox_Bubin1.setValue("");
        GroupBox_Bubin2.setValue("");
        GroupBox_Bubin3.setValue("");
        GroupBox_Hidden.setValue("");
        dlt_dataBook.removeAll();
        coprKsrDstic_tab2.setSelectedIndex(0); //법인KB스타관계구분(선정기준)
        bbrnChoicGrd_tab2.setSelectedIndex(0); //법인KB스타선정등급(영업점선정등급)
        regiYn_tab2.setSelectedIndex(0); //법인KB스타 등록해제구분

        coprKsrDstic_tab2.setDisabled(false); //법인KB스타관계구분(선정기준)
        bbrnChoicGrd_tab2.setDisabled(false); //법인KB스타선정등급구분코드
        //mainCuniqno_tab2.Enabled = true;		//주고객고유번호
        mainCustIdnfr_tab2.setReadOnly(false); //주고객식별자(법인대표자)
        //coprBzmanUniqno_tab2.Enabled = true;	//법인사업자번호
        coprBzmanUniqno_tab2.setReadOnly(false); //법인사업자번호

        Button_tab2_GetFamily.setDisabled(false); //법인스타 가족정보 불러오기 버튼

        $c.iz.tran.setTranID("KAA0441041");
        $c.iz.tran.noLockScreen();
        await $c.tran.ASend();

        //조회후 결과값 save
        scwin.SavedData = this.GetScreenControlData();
    }

    //S-MVP영업점선정고객조회
    if ($c.iz._tran.tranId == "KAA0441041" && $c.iz._tran.bError == false) {
        //본인확인번호
        selfConfirmNo.setValue(cuniqno.getValue().substr(0, 7));

        //선정조회구분코드가 K(법인KB스타)인 경우, tab2 열기	
        if (choicInquryDstcd.getValue() == "K") {
            TAB1.setSelectedTabIndex(1); //법인KB스타
        } else {
            TAB1.setSelectedTabIndex(0); //개인KB스타
        }
        if (dataBook.getTotalRow() > 0) {
            for (var r = 1; r <= dataBook.getTotalRow(); r++) {
                var row_subCuniqno = dlt_dataBook.getCellData(r, "subCuniqno");
                dlt_dataBook.setCellData(r, "subSelfConfirmNo", row_subCuniqno.substr(0, 7));
                var row_mainCuniqno = dlt_dataBook.getCellData(r, "mainCuniqno");
                dlt_dataBook.setCellData(r, "mainSelfConfirmNo", row_mainCuniqno.substr(0, 7));
                if (dlt_dataBook.getCellData(r, "regiYn") == '1') {
                    //등록여부(1:등록,2:해제)
                    dlt_dataBook.setCellData(r, "regiYnNm", "등록");
                } else {
                    dlt_dataBook.setCellData(r, "regiYnNm", "해제");
                }
            }
        }
        if (dmndBrncd.getValue() != "") {
            $c.com.getCommonBrnName(dmndBrncd, dmndBrnName);
        }

        /*
         * 개인사업자번호로 조회시 공동대표인경우 팝업 OPEN
         */
        if (ppsnBsnoJntRpsnYn.getValue() == "1") {
            Link.cuniqno = serchNo.getValue(); // 고객고유번호
            $c.iz.screen.popup("KAA04905001", "DATALINK");
            var tempValue1 = Link.custIdnfr;
            var tempValue2 = Link.custMgtNo;
            if (tempValue1 != "" && typeof(tempValue1) != "undefined") {
                // 고유정보번호 
                serchNoDstcd.setValue("3");
                serchNo.setValue(tempValue1 + tempValue2);
                serchCustIdnfr.setValue(tempValue1);
                serchCustMgtNo.setValue(tempValue2);
            }
        }


        //조회한 고객번호로, 기본 값 채워주기(법인KB스타 탭)
        cuniqno_tab2.setValue(cuniqno.getValue()); //부고객고객번호
        selfConfirmNo_tab2.setValue(cuniqno_tab2.getValue().substr(0, 7)); //부고객본인확인번호
        custnm_tab2.setValue(custnm.getValue()); //부고객고객명
        custIdnfr_tab2.setValue(custIdnfr.getValue()); //부고객고객식별자

        mainCuniqno_tab2.setValue(cuniqno.getValue()); //주고객고유번호
        mainCustNm_tab2.setValue(custnm.getValue()); //주고객명
        mainCustIdnfr_tab2.setValue(custIdnfr.getValue()); //주고객식별자

        coprKsrDstic_tab2.setSelectedIndex(1); //법인KB스타관계구분(선정기준) 1:법인대표자 		

        coprKsrDstic_tab2.setDisabled(true); //선정기준
        //mainCuniqno_tab2.Enabled  = false;	//법인대표자주민번호
        mainCustIdnfr_tab2.setReadOnly(true); //주고객식별자(법인대표자)


        //조회후 결과값 save
        scwin.SavedData = this.GetScreenControlData();
    }

    //법인대표자주민번호 및 법인사업자번호 고객검색 후
    if ($c.iz._tran.tranId == "KAA0490641" && $c.iz._tran.bError == false) {
        //검색된 고객식별자가 없는 경우
        if (serchCustIdnfrT.getValue() == "") {
            if (searchDstic.getValue() == '2') {
                // 검색구분 2:법인사업자번호
                $c.iz.data.alert("해당 사업자번호의 고객정보가 존재하지 않습니다.\n입력 고객번호:" + serchCuniqno_bakcup.getValue(), "안내");
                coprBzmanUniqno_tab2.focus(); //법인사업자번호
            } else {
                $c.iz.data.alert("고객정보가 없습니다. 입력한 고객번호를 확인해주세요.\n입력 고객번호:" + serchCuniqno_bakcup.getValue(), "안내");
                mainCuniqno_tab2.focus(); //법인대표자주민번호
            }
        } else {
            if (searchDstic.getValue() == '1') {
                // 검색구분 1:법인대표자고객번호

                if (serchCustPtrnClsfiDstcd.getValue() == '1') {
                    //고객유형분류 1:개인

                    mainCustNm_tab2.setValue(serchCustnm1.getValue()); //법인대표자주민번호 고객명
                    mainCustIdnfr_tab2.setValue(serchCustIdnfrT.getValue()); //법인대표자주민번호 식별자
                } else {
                    mainCustNm_tab2.setValue("");
                    mainCustIdnfr_tab2.setValue("");
                    $c.iz.data.alert("개인만 가능합니다. 법인대표자 KB-PIN을 확인해주세요.\n고객번호:" + serchCuniqno.getValue() + ", KB-PIN:" + serchCustIdnfrT.getValue() + ", 고객유형:" + serchCustPtrnClsfiDstcd.getValue(), "안내");
                    mainCuniqno_tab2.focus(); //법인대표자주민번호
                }
            } else if (searchDstic.getValue() == '2') {
                // 검색구분 2:법인사업자번호

                if (serchCustPtrnClsfiDstcd.getValue() == '4' || //고객유형분류 4:법인사업자
                    serchCustPtrnClsfiDstcd.getValue() == '5' || //고객유형분류 5:임의단체
                    serchCustPtrnClsfiDstcd.getValue() == '6' || //고객유형분류 6:해외현지법인
                    serchCustPtrnClsfiDstcd.getValue() == '7') {
                    //고객유형분류 7:외국기업

                    coprBzmanNm_tab2.setValue(serchCustnm1.getValue());
                    coprBzmanIdnfr_tab2.setValue(serchCustIdnfrT.getValue());
                } else {
                    coprBzmanNm_tab2.setValue("");
                    coprBzmanIdnfr_tab2.setValue("");
                    $c.iz.data.alert("법인사업자 및 임의단체만 가능합니다. 법인사업자번호를 확인해주세요.\n고객번호:" + serchCuniqno.getValue() + ", KB-PIN:" + serchCustIdnfrT.getValue() + ", 고객유형:" + serchCustPtrnClsfiDstcd.getValue(), "안내");
                    coprBzmanUniqno_tab2.focus(); //법인사업자번호
                }
            }
        }
    }
};


