        selfConfirmNo_tab2.setValue(dlt_dataBook.getCellData(Arg1, "subSelfConfirmNo")); //부고객본인확인번호
        custnm_tab2.setValue(dlt_dataBook.getCellData(Arg1, "subCustNm")); //부고객명
        custIdnfr_tab2.setValue(dlt_dataBook.getCellData(Arg1, "subCustIdnfr")); //부고객식별자

        coprKsrDstic_tab2.setValue(dlt_dataBook.getCellData(Arg1, "coprKsrDstic")); //법인KB스타관계구분(선정기준)
