scwin.Button_Regi_tab2_OnClick = async function(e) {
    //법인KB스타 등록버튼

    //등록시고객식별자체크
    if (custIdnfr.getValue() == "") {
        $c.iz.data.message("KB-PIN이 없습니다. 조회 후 처리하시기 바랍니다.");
        serchNo.focus();
        return false;
    }

    //매월10일전 2영업일 오류처리
    if (jobPrhbYn.getValue() == "Y") {
        $c.iz.data.alert("매월 스타클럽 등급선정일 전 2영업일은 등급선정작업으로 인해 거래가 제한됩니다.", "알림");
        serchNo.focus();
        return false;
    }

    //	var CurrData = this.GetScreenControlData();
    //	if (CurrData == SavedData)  {	
    //	    Alert("변경사항이 없습니다", "");
    //        return false;
    //	}		

    //등록,해제선택
    if (regiYn_tab2.getValue() == "") {
        $c.iz.data.alert("등록, 해제를 선택하여 주십시요", "");
        regiYn_tab2.focus();
        return false;
    }


    //법인KB스타 등록 거래
    if (regiYn_tab2.getValue() == '1') {
        //등록이면서

        //이미 S(S-MVP) 등록상태 체크
        if (choicInquryDstcd.getValue() == 'S') {
            $c.iz.data.alert("현재 S-MVP/개인KB스타 영업점선정등급을 보유하고 있는 고객입니다.\n재선정 필요시 기존 선정등록 내역을 해제 처리 후 재등록하시기 바랍니다.", "중복 선정 불가 안내");
            return false;
        }

        //등록가능고객수 체크
        if (bbrnChoicGrd_tab2.getValue() == '1') {
            //MVP
            if (kBrnRAbilNoitm1.getValue() <= 0) {
                //MVP 한도
                $c.iz.data.alert("영업점 선정 한도 초과로 등록이 불가합니다.(MVP)", "한도 초과 에러");
                return false;
            }
        } else if (bbrnChoicGrd_tab2.getValue() == '2') {
            //로얄
            if (kBrnRAbilNoitm2.getValue() <= 0) {
                //로얄 한도
                $c.iz.data.alert("영업점 선정 한도 초과로 등록이 불가합니다.(로얄)", "한도 초과 에러");
                return false;
            }
        } else if (bbrnChoicGrd_tab2.getValue() == '3') {
            //골드
            if (kBrnRAbilNoitm3.getValue() <= 0) {
                //골드 한도
                $c.iz.data.alert("영업점 선정 한도 초과로 등록이 불가합니다.(골드)", "한도 초과 에러");
                return false;
            }
        }

        //고객번호(부고객) 체크
        if (custIdnfr_tab2.getValue() == '') {
            $c.iz.data.alert("등록할 고객번호가 없습니다. \"법인스타 가족정보 불러오기\" 버튼을 눌러서, 등록할 고객을 선택하세요.\n가족관계가 없는 경우, \"법인대표자\" 본인만 등록 가능합니다.", "알림");
            Button_tab2_GetFamily.focus();
            return false;
        }
    } else if (regiYn_tab2.getValue() == '2') {
        //해제이면서

        //고객번호(부고객) 체크
        if (custIdnfr_tab2.getValue() == '') {
            $c.iz.data.alert("고객번호가 없습니다. 선정 정보 리스트에서 해제할 고객을 선택하세요.", "알림");
            Button_tab2_GetFamily.focus();
            return false;
        }

        //해제하는 부점이, 등록점과 동일한지 체크
        if (regiBrncd_tab2.getValue() != $c.user.getUserProfile('userBzwkBrncd')) {
            $c.iz.data.alert("등록했던 부점에서만 해제가 가능합니다.\n등록점:" + regiBrncd_tab2.getValue() + ", 거래점:" + $c.user.getUserProfile('userBzwkBrncd'), "안내");
            return false;
        }

        //해제버튼 클릭 시 안내 메시지 팝업
        if ($c.iz.data.confirm("선정 해제시 해당 고객의 등급은 당월 은행 실질등급으로 변경됩니다.\n가족합산등급 등 최고등급을 보유하고 있는 고객일 경우 해당 등급은 매월 10일에 반영되오니 고객응대에 참고하시기 바랍니다.", "해제 안내") != true) {
            //취소 선택했을 때
            return false;
        }
    }


    //법인대표자주민번호 체크
    if (mainCustIdnfr_tab2.getValue() == '') {
        $c.iz.data.alert("법인대표자 KB-PIN을 입력해주세요.", "알림");
        //mainCuniqno_tab2.SetFocus();
        mainCustIdnfr_tab2.focus(); //주고객식별자(법인대표자)
        return false;
    }

    //법인사업자번호 체크
    if (coprBzmanIdnfr_tab2.getValue() == '') {
        $c.iz.data.alert("법인사업자번호를 입력해주세요.", "알림");
        coprBzmanUniqno_tab2.focus();
        return false;
    }

    //선정기준 체크
    if (coprKsrDstic_tab2.getValue() == '00') {
        // 선정기준 (00:해당무)
        $c.iz.data.alert("선정기준을 00(해당무)로 등록할 수 없습니다. 선정기준을 확인해주세요.", "알림");
        coprKsrDstic_tab2.focus();
        return false;
    }

    //선정기준 체크(배우자, 자녀인 경우, 부고객번호와 주고객번호가 같을 수가 없다.
    if (coprKsrDstic_tab2.getValue() != '01') {
        // 선정기준 (01:법인대표자가 아닌)

        var strKsrName = "";
        if (coprKsrDstic_tab2.getValue() == '02') {
            // 선정기준 (02:법인배우자)
            strKsrName = "법인배우자";
        } else if (coprKsrDstic_tab2.getValue() == '03') {
            // 선정기준 (02:법인자녀)
            strKsrName = "법인자녀";
        } else {
            strKsrName = "해당무";
        }

        //고객고유번호로 비교
        if (cuniqno_tab2.getValue() == mainCuniqno_tab2.getValue()) {
            $c.iz.data.alert("등록 대상 고객과 법인대표자가 동일합니다. 선정기준을 확인 후, 다시 거래해주세요.\n입력된 선정기준 : " + strKsrName, "알림");
            mainCustIdnfr_tab2.focus();
            return false;
        }
        //고객식별자로 비교
        if (custIdnfr_tab2.getValue() == mainCustIdnfr_tab2.getValue()) {
            $c.iz.data.alert("등록 대상 고객과 법인대표자가 동일합니다. 선정기준을 확인 후, 다시 거래해주세요.\n입력된 선정기준 : " + strKsrName, "알림");
            mainCustIdnfr_tab2.focus();
            return false;
        }
    }

    //영업점선정등급 체크
    if (bbrnChoicGrd_tab2.getValue() == '0') {
        $c.iz.data.alert("영업점선정등급을 0(해당무)로 등록할 수 없습니다. 영업점선정등급을 확인해주세요.", "알림");
        bbrnChoicGrd_tab2.focus();
        return false;
    }
    $c.iz.tran.setTranID("KAA0641661");
    $c.iz.tran.noLockScreen();
    await $c.tran.ASend();
};

scwin.coprKsrDstic_tab2_OnItemChanged = function(info) {
    //법인KB스타관계구분(선정기준)

    if (coprKsrDstic_tab2.getValue() == '01') {
        //01:법인대표자(본인)
        if (custIdnfr_tab2.getValue() == "") {
            //(부)고객식별자가 없는 경우, 조회된 고객번호로 셋팅

            //조회한 고객번호로, 기본 값 채워주기(법인KB스타 탭)
            cuniqno_tab2.setValue(cuniqno.getValue()); //부고객고객번호
            selfConfirmNo_tab2.setValue(cuniqno_tab2.getValue().substr(0, 7)); //부고객본인확인번호
            custnm_tab2.setValue(custnm.getValue()); //부고객고객명
            custIdnfr_tab2.setValue(custIdnfr.getValue()); //부고객고객식별자

            mainCuniqno_tab2.setValue(cuniqno.getValue()); //주고객고유번호
            mainCustNm_tab2.setValue(custnm.getValue()); //주고객명
            mainCustIdnfr_tab2.setValue(custIdnfr.getValue()); //주고객식별자
        } else {
            //부고객번호로 법인대표자 고객번호 채우기
            mainCuniqno_tab2.setValue(cuniqno_tab2.getValue()); //법인대표자주민번호 = (부)고객번호
            mainCustNm_tab2.setValue(custnm_tab2.getValue()); //법인대표자명		 = (부)고객명
            mainCustIdnfr_tab2.setValue(custIdnfr_tab2.getValue()); //법인대표자식별자 	 = (부)고객식별자
        }

        //mainCuniqno_tab2.Enabled = false;	//법인대표자주민번호
        mainCustIdnfr_tab2.setReadOnly(true); //주고객식별자(법인대표자)
    } else {
        //		mainCuniqno_tab2.Clear();	//법인대표자주민번호
        //		mainCustNm_tab2.Clear();	//법인대표자명
        //		mainCustIdnfr_tab2.Clear();	//법인대표자고객식별자

        //mainCuniqno_tab2.Enabled = true;	//법인대표자주민번호
        mainCustIdnfr_tab2.setReadOnly(false); //주고객식별자(법인대표자)
    }
};

