scwin.CheckBox_noFamily_OnItemChanged = function(info) {
    //가족관계 없음 체크박스

    //조회된 고객번호가 있는지 체크
    if (custIdnfr.getValue() != "") {
        //가족관계가 없는 경우(본인이 법인사업자 대표자인 경우로 판단)
        if (CheckBox_noFamily.IsChecked == true) {
            $c.iz.data.alert("가족관계가 없는 고객인 경우, 법인대표자로만 등록 가능합니다.", "안내");

            //가족관계가 없는 경우(본인이 법인사업자 대표자인 경우로 판단)
            cuniqno_tab2.setValue(cuniqno.getValue()); //부고객고객번호
            selfConfirmNo_tab2.setValue(cuniqno_tab2.getValue().substr(0, 7)); //부고객본인확인번호
            custnm_tab2.setValue(custnm.getValue()); //부고객고객명
            custIdnfr_tab2.setValue(custIdnfr.getValue()); //부고객고객식별자

            mainCuniqno_tab2.setValue(cuniqno.getValue()); //주고객고유번호
            mainCustNm_tab2.setValue(custnm.getValue()); //주고객명
            mainCustIdnfr_tab2.setValue(custIdnfr.getValue()); //주고객식별자

            coprKsrDstic_tab2.setSelectedIndex(1); //법인KB스타관계구분(선정기준) 1:법인대표자
            coprKsrDstic_tab2.setDisabled(true); //법인KB스타관계구분(선정기준)

            //mainCuniqno_tab2.Enabled  = false;	//주고객고유번호
            mainCustIdnfr_tab2.setReadOnly(true); //주고객식별자(법인대표자)

            Button_tab2_GetFamily.setDisabled(true); //법인스타 가족정보 불러오기 버튼
        } else {
            coprKsrDstic_tab2.setSelectedIndex(0); //법인KB스타관계구분(선정기준) 1:법인대표자
            coprKsrDstic_tab2.setDisabled(false); //법인KB스타관계구분(선정기준)

            //mainCuniqno_tab2.Enabled  = true;		//주고객고유번호
            mainCustIdnfr_tab2.setReadOnly(false); //주고객식별자(법인대표자)

            Button_tab2_GetFamily.setDisabled(false); //법인스타 가족정보 불러오기 버튼
        }
    } else {
        $c.iz.data.alert("고객정보가 유효하지 않습니다.\n조회 후, 거래하세요.", "안내");
        CheckBox_noFamily.setValue("");
        serchNo.focus();
        return;
    }
};

scwin.TAB1_OnItemChanged = function(info) {
    //탭을 바꿀때, 기등록정보 종류 체크

    if (choicInquryDstcd.getValue() == 'S') {
        //S : S-MVP/개인KB스타가 등록되어 있는 고객
        if (TAB1.getSelectedTabIndex() == '1') {
            //법인KB스타대표/가족 탭
            $c.iz.data.alert("현재 S-MVP/개인KB스타 영업점선정등급을 보유하고 있는 고객입니다.\n재선정 필요시 기존 선정등록 내역을 해제 처리 후 재등록하시기 바랍니다.", "중복 선정 불가 안내");
            return false;
        }
    } else if (choicInquryDstcd.getValue() == 'K') {
        //K : 법인KB스타가 등록되어 있는 고객
        if (TAB1.getSelectedTabIndex() == '0') {
            //S-MVP/개인KB스타 탭
            $c.iz.data.alert("현재 법인KB스타대표/가족 등급을 보유하고 있는 고객입니다.\n재선정 필요시 기존 선정등록 내역을 해제 처리 후 재등록하시기 바랍니다.", "중복 선정 불가 안내");
            return false;
        }
    }
};

